        <li>ANC Visit Conflicts : 1210</li>
        <li>Blood Sugar Conflicts : 451</li>
        <li>Blood Pressure Conflicts : 364</li>
        <li>Weight Conflicts : 93</li>
        <li>Haemoglobin Conflicts : 26</li>
      </ul>

    </div>
  );
}
